#include<bits/stdc++.h>
using namespace std;
int main()
{
	int a;
	cin>>a;
	int b[a];
	for(int i=0;i<a;i++)
	{
		cin>>b[i];
	}
	int c;
	cin>>c;
	for(int i=0;i<a;i++)
	{
		if(b[i]==c)
		{
			cout<<i+1;
			return 0;
		}
	}
	return 0;
}
